var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"으아아아아……! 비가 엄청나게 쏟아지잖아……!","JPN":"うわああああ……！　めちゃくちゃ降ってる……！","ENG":"Nooooo...! It’s pouring outside...!","TWN":"哎啊啊啊……！雨下好大……！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"누나들은 왜 하필 날짜를 골라도 이런 날에, 이런 시간에 오라는 거야?","JPN":"なんでよりによってこんな日の、こんな時間に来いなんて言うんだ。","ENG":"Why did it have to be this day, at this hour?","TWN":"她們怎麼偏偏挑天氣不好的時候叫我來啦！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"저기 보인다! 가면 다 젖기 전에 빨리 뛰자!","JPN":"校舎が見えた！　ずぶ濡れになる前に走ろう！","ENG":"There it is! I should run before my mask gets drenched.","TWN":"在那裡！快跑過去吧，否則面具會濕掉的！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"뭐, 뭐야? 설마 아무도 없는 거야? 불도 꺼져 있고…….","JPN":"な、なんだ？　まさか誰もいないとか？　電気も消えてるし……","ENG":"W-what’s going on? Is anyone here? All the lights are off...","TWN":"嗯？怎麼回事？沒人在嗎？連燈也沒開……"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"이렇게 늦은 시간에 불러 놓고 대체 어딜…… 정말 다들 속을 모르겠다니까…….","JPN":"こんな遅い時間に呼び出しておいて、いったいどこに居るんだ……本当にみんな何考えてるんだか……","ENG":"Why would they look for me and disappear...? Geez, I don’t get these girls...","TWN":"這麼晚還把人家叫過來，結果人咧……真猜不透她們……"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"으아아아앗! 보라 누나! 깜짝 놀랐잖아요, 언제부터 거기 있던 거예요!?","JPN":"うわあああっ！　シホさん！　ビックリしたじゃないですか、いつからそこにいたんですか！？","ENG":"Aaaaaagh! Bora! You scared me! How long were you standing there?!","TWN":"啊啊啊啊！寶拉姊姊！你是想嚇死我嗎！你從什麼時候開始站在這的！？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……부터.","JPN":"……から。","ENG":"From...","TWN":"……從。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>설마 아무도 없나?</color>부터.","JPN":"……<color=#ffd34c>まさか誰もいないとか？</color>から。","ENG":"...When you said, <color=#ffd34c>\\"Is anyone here?\\"</color>","TWN":"……<color=#ffd34c>沒人在嗎？</color>的時候。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, 그럼 처음부터 있었다는 뜻이잖아요! 불 꺼놓고 뭘 하고 있었던 거예요!","JPN":"じゃ、じゃあ、最初からいたってことじゃないですか！　電気も消して、いったい何をしてたんですか！","ENG":"Th-that means you were here all along! What were you doing in the dark?!","TWN":"那…那不就是你從一開始就在的意思嗎？幹嘛不開燈啦！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하고 있었어……. 디버깅.","JPN":"やってた……デバッグ。","ENG":"I was... debugging.","TWN":"我在……除錯。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, 그래요! 디버깅! 디버깅한다면서요! 그럼, 다른 누나들은요?","JPN":"そ、そうですよ！　デバッグ！　デバッグするって！　じゃあ、他のみんなは？","ENG":"O-okay! Debugging! We were going to debug stuff! Where are the others?","TWN":"喔，喔喔～除錯喔！你剛在除錯喔！那其他人呢？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하고 있어…… <color=#ffd34c>현장 실습</color>.","JPN":"遅くなる……やってるから……<color=#ffd34c>現場実習</color>。","ENG":"They’re coming in late... <color=#ffd34c>Field training</color>… they're doing.","TWN":"遲到……她們……<color=#ffd34c>現場實習</color>。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"에엥? 실습이라고요? 이런 날씨에? 이런 시간에?","JPN":"ええっ？　実習ですか？　こんな天気に？　こんな時間に？","ENG":"Eh? Field training? In this weather? At this hour?","TWN":"什麼？你說實習？這種天氣？這個時間？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그럼, 누나는요?","JPN":"じゃあ、シホさんは？","ENG":"What about you?","TWN":"那你呢？"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"나는 아니거든……. 현장 타입. 그러니까…….","JPN":"私は向いてない……現場。だから……","ENG":"I’m not... the field type. So...","TWN":"我不適合……現場，所以……"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};